import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi, } from "vitest";
import { arm, disarm } from "./arming.js";
import * as client from "./client.js";
import { captureFromHook } from "./index.js";
function writeTranscript(dir, lines) {
    const file = path.join(dir, "transcript.jsonl");
    const content = `${lines.map((l) => JSON.stringify(l)).join("\n")}\n`;
    fs.writeFileSync(file, content);
    return file;
}
function makeTurnRecord(role, text, ts) {
    return {
        type: "message",
        timestamp: ts ?? new Date().toISOString(),
        message: { role, content: text },
    };
}
describe("captureFromHook cleanup behavior", () => {
    let tempHome;
    let transcriptDir;
    let appendSpy;
    let stateSpy;
    const originalHome = process.env.HOME;
    const originalEnv = process.env.BITFAB_CAPTURE_SESSIONS;
    beforeEach(() => {
        tempHome = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-capture-"));
        transcriptDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-transcript-"));
        process.env.HOME = tempHome;
        process.env.BITFAB_CAPTURE_SESSIONS = "1";
        appendSpy = vi.spyOn(client, "appendChatSession");
        stateSpy = vi.spyOn(client, "getChatSessionState");
        stateSpy.mockResolvedValue(null);
    });
    afterEach(() => {
        process.env.HOME = originalHome;
        if (originalEnv === undefined) {
            delete process.env.BITFAB_CAPTURE_SESSIONS;
        }
        else {
            process.env.BITFAB_CAPTURE_SESSIONS = originalEnv;
        }
        fs.rmSync(tempHome, { recursive: true, force: true });
        fs.rmSync(transcriptDir, { recursive: true, force: true });
        vi.restoreAllMocks();
    });
    function makeInput(transcriptPath) {
        return {
            session_id: "test-session",
            transcript_path: transcriptPath,
            cwd: transcriptDir,
        };
    }
    it("cleans up armed state after successful Stop flush", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 100,
            turnCount: 1,
        });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(false);
    });
    it("ignores SubagentStop entirely: no flush, no disarm of the live session", async () => {
        // SubagentStop carries the MAIN session_id but the subagent's transcript.
        // Treating it as terminal (the old behaviour) flushed the wrong transcript
        // and disarmed the still-running main session, dropping everything after the
        // first subagent. It must be a hard no-op instead.
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        const result = await captureFromHook("SubagentStop", makeInput(transcriptPath));
        expect(result.status).toBe("skipped_subagent_stop");
        // Never touched the server, and the main session stays armed so its later
        // turns keep getting captured.
        expect(appendSpy).not.toHaveBeenCalled();
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(true);
    });
    it("keeps capturing the main session AFTER a subagent finishes", async () => {
        // The regression: the old code disarmed on SubagentStop, so everything the
        // main agent did after the first subagent was dropped (skipped_not_armed).
        // Returning offset 0 each time keeps the mock simple: every flush re-reads
        // the whole transcript, so a grown file always yields turns.
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "u1"),
            makeTurnRecord("assistant", "a1"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 0,
            turnCount: 2,
        });
        // First flush captures the opening turns.
        const first = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(first.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledTimes(1);
        // A subagent finishes: no-op, no send, still armed.
        const sub = await captureFromHook("SubagentStop", makeInput(transcriptPath));
        expect(sub.status).toBe("skipped_subagent_stop");
        expect(appendSpy).toHaveBeenCalledTimes(1);
        // The main agent keeps working. THE PROOF: this is still captured, not
        // skipped_not_armed.
        fs.appendFileSync(transcriptPath, `${JSON.stringify(makeTurnRecord("user", "u2"))}\n${JSON.stringify(makeTurnRecord("assistant", "a2"))}\n`);
        const cont = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(cont.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledTimes(2);
    });
    it("preserves armed state when Stop flush fails with network error", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: false,
            reason: "network",
            detail: "connection refused",
        });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("error");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(true);
    });
    it("preserves armed state when Stop flush fails with auth error", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({ ok: false, reason: "auth" });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("auth_missing");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        expect(fs.existsSync(armedFile)).toBe(true);
    });
    it("preserves armed state when Stop flush hits offset conflict", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: false,
            reason: "offset_conflict",
            lastTranscriptOffset: 50,
            turnCount: 1,
            nextSequence: 8,
        });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("no_op");
        const armedFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.armed");
        // offset_conflict returns no_op which is treated as safe to clean up,
        // because the server already has the data and resynced the offset
        expect(fs.existsSync(armedFile)).toBe(false);
    });
    it("preserves server nextSequence after offset conflict", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockResolvedValue({
            ok: false,
            reason: "offset_conflict",
            lastTranscriptOffset: 50,
            turnCount: 1,
            nextSequence: 8,
        });
        const result = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(result.status).toBe("no_op");
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        expect(JSON.parse(fs.readFileSync(offsetFile, "utf-8"))).toEqual({
            offset: 50,
            sequenceBase: 8,
        });
    });
    it("does not recreate offset state when a background flush finishes after Stop cleanup", async () => {
        const transcriptPath = writeTranscript(transcriptDir, [
            makeTurnRecord("user", "hello"),
        ]);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        appendSpy.mockImplementation(async () => {
            disarm("test-session");
            return {
                ok: true,
                id: "sess-1",
                lastTranscriptOffset: 100,
                turnCount: 1,
            };
        });
        const result = await captureFromHook("PreToolUse", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        expect(fs.existsSync(offsetFile)).toBe(false);
    });
    it("sends ended flag during compaction even with zero new turns", async () => {
        const transcriptPath = writeTranscript(transcriptDir, []);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        // Write an offset state that's larger than the current file size to
        // trigger the compaction path
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        fs.writeFileSync(offsetFile, JSON.stringify({ offset: 99999 }));
        stateSpy.mockResolvedValue({
            exists: true,
            lastTranscriptOffset: 50,
            turnCount: 2,
            status: "active",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: 0,
            turnCount: 2,
        });
        const result = await captureFromHook("Stop", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledWith(expect.objectContaining({
            ended: true,
            compacted: true,
        }));
    });
    it("returns no_op for compaction with zero turns on non-terminal hook", async () => {
        const transcriptPath = writeTranscript(transcriptDir, []);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        fs.writeFileSync(offsetFile, JSON.stringify({ offset: 99999 }));
        stateSpy.mockResolvedValue({
            exists: true,
            lastTranscriptOffset: 50,
            turnCount: 2,
            status: "active",
        });
        const result = await captureFromHook("PreCompact", makeInput(transcriptPath));
        expect(result.status).toBe("no_op");
        expect(appendSpy).not.toHaveBeenCalled();
    });
    it("uses remote nextSequence rather than turnCount after compaction", async () => {
        const transcriptPath = path.join(transcriptDir, "transcript.jsonl");
        fs.writeFileSync(transcriptPath, `${JSON.stringify(makeTurnRecord("user", "after compaction"))}\nnot-json\n${JSON.stringify(makeTurnRecord("assistant", "ack"))}\n`);
        arm("test-session", {
            transcriptPath,
            cwd: transcriptDir,
            agent: "claude-code",
        });
        const offsetFile = path.join(tempHome, ".config", "bitfab", "sessions", "test-session.offset");
        fs.writeFileSync(offsetFile, JSON.stringify({ offset: 99999 }));
        stateSpy.mockResolvedValue({
            exists: true,
            lastTranscriptOffset: 50,
            turnCount: 2,
            nextSequence: 8,
            status: "active",
        });
        appendSpy.mockResolvedValue({
            ok: true,
            id: "sess-1",
            lastTranscriptOffset: fs.statSync(transcriptPath).size,
            turnCount: 4,
        });
        const result = await captureFromHook("PostToolUse", makeInput(transcriptPath));
        expect(result.status).toBe("appended");
        expect(appendSpy).toHaveBeenCalledWith(expect.objectContaining({
            compacted: true,
            turns: [
                expect.objectContaining({ sequence: 8 }),
                expect.objectContaining({ sequence: 10 }),
            ],
        }));
    });
});
